import{C as o,o as s,c as n,a5 as e,E as r}from"./chunks/framework.CW28V7p_.js";const h=JSON.parse('{"title":"4. SFDP & stake pools","description":"","frontmatter":{},"headers":[],"relativePath":"module-7/4-sfdp-pools.md","filePath":"module-7/4-sfdp-pools.md","lastUpdated":1780937944000}'),l={name:"module-7/4-sfdp-pools.md"},g=Object.assign(l,{setup(d){const t={id:"m7-4-sfdp-pools",title:"🧠 Mini-check: SFDP & pools",intro:"2 питання.",questions:[{type:"compare",q:"SFDP vs Stake pools (Jito, Marinade)?",ideal:`SFDP (Solana Foundation Delegation Program):
- Anza/Foundation delegates "matching" stake до qualifying validators
- Free для validator (no fee)
- Requires meeting performance + decentralization criteria (geographic, software diversity, performance metrics)
- Significant boost для new validators getting started
- Can be removed якщо performance дроп

Stake pools:
- Smart contracts collecting retail SOL (users mint liquid token: JitoSOL, mSOL, INF, etc.)
- Algorithmically delegate до approved validators
- Pay validator like normal delegation (commission applies)
- Approved validators chosen by pool DAO/manager based on performance criteria
- More transparent than SFDP, governed by tokens (JitoDAO, etc.)

Both provide stake to validators meeting standards. SFDP free + Foundation backed. Pools democratic + community governed.`,explanation:"Module 7.4."},{type:"mcq",q:"Що з цього вірно про StakeNet Steward Config (per memory)?",options:["Validator must meet specific criteria для qualifying у Steward pool","JIP-28 ongoing 100% tier (active stake delegation)","Criteria НЕ те ж саме що JIP-31/37 cash subsidy criteria","Steward Config документація — canonical source для exact thresholds"],correct:[0,1,2,3],explanation:"Steward Config separate from JIPs cash. Critical distinction (per memory feedback). Module 7.4."}]};return(p,a)=>{const i=o("Quiz");return s(),n("div",null,[a[0]||(a[0]=e(`<h1 id="_4-sfdp-stake-pools" tabindex="-1">4. SFDP &amp; stake pools <a class="header-anchor" href="#_4-sfdp-stake-pools" aria-label="Permalink to &quot;4. SFDP &amp; stake pools&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>SFDP</strong> (Solana Foundation Delegation Program) — Foundation delegates stake до qualifying validators (free). <strong>Stake pools</strong> — Jito/Marinade/etc. — community DAO-governed pools delegating retail SOL до approved validators. Both critical income streams для validators.</p><h2 id="sfdp" tabindex="-1">SFDP <a class="header-anchor" href="#sfdp" aria-label="Permalink to &quot;SFDP&quot;">​</a></h2><p><strong>Solana Foundation Delegation Program</strong>: Anza/Foundation runs program where Foundation matches up to N SOL stake to validators meeting decentralization + performance criteria.</p><p>Criteria (приблизно):</p><ul><li><strong>Performance</strong>: skip rate &lt; threshold, vote credits high</li><li><strong>Software diversity</strong>: not over-concentrated на one version</li><li><strong>Geographic diversity</strong>: not all validators у same region</li><li><strong>Identity</strong>: known operator, not anonymous shell</li><li><strong>Decentralization</strong>: not too much stake from one source</li></ul><p>Benefit:</p><ul><li>Free additional stake (no commission earned but boosts validator size)</li><li>Stay у &quot;tier 1&quot; voting weight</li><li>Reputation signal (Foundation-vetted)</li></ul><p>Negative:</p><ul><li>Can be removed quickly якщо performance drops</li><li>Not infinite (capped per validator)</li></ul><h2 id="stake-pools" tabindex="-1">Stake pools <a class="header-anchor" href="#stake-pools" aria-label="Permalink to &quot;Stake pools&quot;">​</a></h2><p><strong>Stake pools</strong> — smart contracts collecting retail SOL → delegating to approved validators → issuing <strong>liquid staking tokens</strong> (LSTs).</p><p>Major pools:</p><table tabindex="0"><thead><tr><th>Pool</th><th>LST</th><th>Approach</th></tr></thead><tbody><tr><td><strong>Jito</strong></td><td>JitoSOL</td><td>MEV-aware, performance-focused</td></tr><tr><td><strong>Marinade</strong></td><td>mSOL</td><td>Algorithmic delegation, validator scoring</td></tr><tr><td><strong>Sanctum</strong></td><td>INF + ind. LSTs</td><td>Infrastructure для LSTs</td></tr><tr><td><strong>Lido</strong></td><td>(formerly stSOL, sunsetted)</td><td>—</td></tr></tbody></table><p>User wants stake but want liquidity → deposit SOL → receive LST (1:1 initially, then accumulates rewards). Sell/use LST у DeFi while underlying SOL earns rewards.</p><p>Pool managers/DAOs decide validator set based on criteria similar to SFDP.</p><h3 id="stakenet-steward" tabindex="-1">StakeNet Steward <a class="header-anchor" href="#stakenet-steward" aria-label="Permalink to &quot;StakeNet Steward&quot;">​</a></h3><p>StakeNet — system для governing stake pool delegations через on-chain config. Per memory <code>feedback_verify_validator_criteria_from_official_sources.md</code>:</p><p>⚠️ <strong>Critical</strong>: StakeNet <strong>Steward Config</strong> thresholds ≠ JIP-31/37 cash subsidy criteria. Different programs. Always check <strong>canonical official sources</strong> для exact criteria.</p><h3 id="jito-jip-28-per-memory" tabindex="-1">Jito JIP-28 (per memory) <a class="header-anchor" href="#jito-jip-28-per-memory" aria-label="Permalink to &quot;Jito JIP-28 (per memory)&quot;">​</a></h3><ul><li>Ongoing JitoSOL delegation</li><li>100% tier active</li><li>Eligible validators chosen за StakeNet Steward Config criteria</li><li>Specific thresholds у docs (не paraphrase from memory без verifying)</li></ul><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><h3 id="mainnet-income-breakdown-typical" tabindex="-1">Mainnet income breakdown (typical) <a class="header-anchor" href="#mainnet-income-breakdown-typical" aria-label="Permalink to &quot;Mainnet income breakdown (typical)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LumLabs mainnet validator income:</span></span>
<span class="line"><span>├─ Foundation delegated stake (SFDP) — boosts rewards</span></span>
<span class="line"><span>├─ Jito stake pool delegation (JitoSOL via StakeNet)</span></span>
<span class="line"><span>├─ Direct delegators (individuals, treasuries)</span></span>
<span class="line"><span>├─ Self-stake</span></span>
<span class="line"><span>└─ Plus Jito tips (MEV) — bonus income</span></span></code></pre></div><h3 id="check-delegations-to-твои-validator" tabindex="-1">Check delegations to твой validator <a class="header-anchor" href="#check-delegations-to-твои-validator" aria-label="Permalink to &quot;Check delegations to твой validator&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stakes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YOUR_MAINNET_VOTE_PUBKEY</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mainnet-beta</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -30</span></span></code></pre></div><p>Show всі stake accounts delegated. Можна group by staker to see SFDP, Jito, etc.</p><h2 id="hands-on" tabindex="-1">Hands-on <a class="header-anchor" href="#hands-on" aria-label="Permalink to &quot;Hands-on&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Alpenglow self-stake</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag/bin/solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stakes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 3GDBUfmTyL9d3KDb84zc1vUFCj8znunCEYpKuzsEdkeo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8899</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Mainnet stake breakdown (with explorer URL pre-built)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://stakewiz.com/validator/YOUR_MAINNET_VOTE_PUBKEY&quot;</span></span></code></pre></div><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,31)),r(i,{data:t}),a[1]||(a[1]=e('<h2 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h2><p><a href="/glossary#s"><code>SFDP</code></a>, <a href="/glossary#s"><code>Stake pool</code></a>, <a href="/glossary#l"><code>LST</code></a>, <a href="/glossary#l"><code>Liquid staking token</code></a>, <a href="/glossary#j"><code>JitoSOL</code></a>, <a href="/glossary#m"><code>mSOL</code></a>, <a href="/glossary#s"><code>StakeNet</code></a>, <a href="/glossary#s"><code>Steward Config</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://solana.org/delegation-program" target="_blank" rel="noreferrer">SFDP overview</a></li><li><a href="https://docs.jito.network/stakenet" target="_blank" rel="noreferrer">Jito StakeNet docs</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-7/3-mev-jito">← 3. MEV/Jito</a> | <strong>Наступне:</strong> <a href="/module-7/final-quiz">⭐ Final quiz →</a></p>',6))])}}});export{h as __pageData,g as default};
